/**
 * _icons — Shared Icon SVG Constants for Preview Generators
 *
 * Central module exporting all Fluent UI System Icon SVG strings used
 * across the preview HTML generators. Each constant is a raw SVG string
 * with `fill="currentColor"` so the parent element's CSS `color` controls
 * the icon tint.
 *
 * Naming convention:
 *   - `{name}Ico`      — 20px icons from shell/nav
 *   - `{name}R{size}`  — Regular variant at given size (e.g. `imgR20`)
 *   - `{name}F{size}`  — Filled variant at given size  (e.g. `imgF20`)
 *   - `{name}{size}`   — Size-specific variants (e.g. `dx20`, `circ16`)
 *
 * Usage:
 *   import { copilotIco, dismissIco, boldR, boldF } from './_icons';
 */

// ─── Shell / Nav Icons (20px) ───────────────────────────────────────

